
DROP TABLE IF EXISTS patients;
CREATE TABLE patients (
  patient_id VARCHAR(36),
  name VARCHAR(255),
  age INT,
  gender VARCHAR(255),
  chronic_condition VARCHAR(255),
  registration_date DATE,
  state VARCHAR(255),
  blood_pressure_systolic INT,
  blood_pressure_diastolic INT,
  cholesterol_level INT,
  hdl_cholesterol INT,
  ldl_cholesterol INT,
  triglycerides INT,
  weight_kg INT,
  height_cm INT,
  bmi DECIMAL(10,2),
  smoker VARCHAR(255),
  alcohol_consumption VARCHAR(255),
  exercise_frequency VARCHAR(255),
  diet_quality VARCHAR(255),
  insurance_type VARCHAR(255),
  income_bracket VARCHAR(255),
  education_level VARCHAR(255),
  PRIMARY KEY (patient_id)
);


DROP TABLE IF EXISTS visits;
CREATE TABLE visits (
  visit_id VARCHAR(36),
  patient_id VARCHAR(36),
  visit_date DATE,
  diagnosis VARCHAR(255),
  procedure VARCHAR(255),
  doctor_name VARCHAR(255),
  visit_duration_minutes INT,
  satisfaction_score INT,
  wait_time_minutes INT,
  follow_up_required VARCHAR(255),
  severity_level VARCHAR(255),
  visit_type VARCHAR(255),
  referral_needed VARCHAR(255),
  medications_prescribed INT,
  PRIMARY KEY (visit_id)
);


DROP TABLE IF EXISTS billing;
CREATE TABLE billing (
  bill_id VARCHAR(36),
  visit_id VARCHAR(36),
  amount DECIMAL(10,2),
  status VARCHAR(255),
  payment_date DATE,
  insurance_coverage_percent INT,
  patient_responsibility DECIMAL(10,2),
  payment_method VARCHAR(255),
  outstanding_balance INT,
  billing_category VARCHAR(255),
  discount_applied INT,
  PRIMARY KEY (bill_id)
);


DROP TABLE IF EXISTS lab_results;
CREATE TABLE lab_results (
  result_id VARCHAR(36),
  patient_id VARCHAR(36),
  test_date DATE,
  test_type VARCHAR(255),
  glucose_level DECIMAL(10,2),
  hemoglobin DECIMAL(10,2),
  white_blood_cell_count DECIMAL(10,2),
  platelet_count INT,
  creatinine DECIMAL(10,2),
  alt INT,
  ast INT,
  result_status VARCHAR(255),
  PRIMARY KEY (result_id)
);


